sql:
SELECT class_type, COUNT(*) AS class_type_count
FROM character_classes
GROUP BY class_type;

SELECT COUNT(*) AS skill_count
FROM skills
WHERE class_id = (SELECT class_id FROM character_classes WHERE class_name = 'Warrior');

SELECT class_name
FROM character_classes
ORDER BY class_name ASC;

external_knowledge:
; Character classes are the unique roles or professions that characters can take in a game; 
; Mana cost refers to the amount of magical energy required to use a skill in a game; 
; Quests are tasks or missions that characters can complete in a game to gain rewards; 
; XP stands for experience points, which characters earn by completing quests or defeating enemies in a game, and are used to level up; 
; Equipment base stats refer to the inherent attack or defense values of items or gear that characters can use in a game.

